import React, { useState } from "react";
import {
    Card,
    CardBody,
    Container,
    Row,
    Col,
    Form,
    FormGroup,
    Label,
    Input,
    Button,
} from "reactstrap";
import { useNavigate } from "react-router-dom";
import Header from "components/Headers/Header.js";

const AddHealthInsurance = () => {
    const navigate = useNavigate();
    const [healthInsurance, setHealthInsurance] = useState({
        code: "",
        fullName: "",
        placeOfRegistration: "",
        validity: "",
        serialNumber: "",
        currency: "VND",
        issueDate: "",
        placeOfIssue: "",
    });

    // Handle input changes
    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setHealthInsurance({ ...healthInsurance, [name]: value });
    };

    // Handle form submission
    const handleSubmit = (e) => {
        e.preventDefault();
        console.log("Health Insurance Submitted:", healthInsurance);
        navigate("/admin/health-insurance-list");
    };

    return (
        <>
            <Header />
            <Container fluid className="mt-4">
                <Row>
                    <Col>
                        <h3 className="text-dark">Thêm Thẻ BHYT</h3>
                        <p className="text-muted">Quản Lý Thẻ BHYT / Thêm Thẻ BHYT</p>
                    </Col>
                </Row>

                <Card className="mt-4">
                    <CardBody>
                        <Row>
                            <Col md="6">
                                <h4 className="text-dark">Thông tin cơ bản</h4>
                                <Form onSubmit={handleSubmit}>
                                    <FormGroup>
                                        <Label for="code">Mã Thẻ</Label>
                                        <Input type="text" id="code" name="code" placeholder="Nhập mã thẻ" value={healthInsurance.code} onChange={handleInputChange} required />
                                    </FormGroup>
                                    <FormGroup>
                                        <Label for="fullName">Họ và Tên</Label>
                                        <Input type="text" id="fullName" name="fullName" placeholder="Nhập họ và tên" value={healthInsurance.fullName} onChange={handleInputChange} required />
                                    </FormGroup>
                                    <FormGroup>
                                        <Label for="placeOfRegistration">Nơi Đăng Ký Khám</Label>
                                        <Input type="text" id="placeOfRegistration" name="placeOfRegistration" placeholder="Nhập nơi đăng ký khám" value={healthInsurance.placeOfRegistration} onChange={handleInputChange} required />
                                    </FormGroup>
                                    <FormGroup>
                                        <Label for="validity">Giá Trị Sử Dụng</Label>
                                        <Input type="date" id="validity" name="validity" value={healthInsurance.validity} onChange={handleInputChange} required />
                                    </FormGroup>
                                    <FormGroup>
                                        <Label for="serialNumber">Mã Số</Label>
                                        <Input type="text" id="serialNumber" name="serialNumber" placeholder="Nhập mã số" value={healthInsurance.serialNumber} onChange={handleInputChange} required />
                                    </FormGroup>
                                    <FormGroup>
                                        <Label for="issueDate">Ngày Cấp</Label>
                                        <Input type="date" id="issueDate" name="issueDate" value={healthInsurance.issueDate} onChange={handleInputChange} required />
                                    </FormGroup>
                                    <FormGroup>
                                        <Label for="placeOfIssue">Nơi Cấp</Label>
                                        <Input type="text" id="placeOfIssue" name="placeOfIssue" placeholder="Nhập nơi cấp" value={healthInsurance.placeOfIssue} onChange={handleInputChange} required />
                                    </FormGroup>
                                    <Button color="success" type="submit" className="mr-2">Lưu Lại</Button>
                                    <Button color="danger" onClick={() => navigate("/admin/health-insurance-list")}>
                                        Quay lại
                                    </Button>
                                </Form>
                            </Col>
                        </Row>
                    </CardBody>
                </Card>
            </Container>
        </>
    );
};

export default AddHealthInsurance;
